import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"全部功能","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"portfolio-and-statements/all-features.md","filePath":"zh-CN/portfolio-and-statements/all-features.md"}'),h={name:"portfolio-and-statements/all-features.md"};function o(l,t,b,i,n,s){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="全部功能" tabindex="-1">全部功能 <a class="header-anchor" href="#全部功能" aria-label="Permalink to &quot;全部功能&quot;">​</a></h1><p>全部功能页汇集了资产 Tab 的所有操作入口，按功能类别分组排列。右上角「管理」可自定义哪些功能显示在资产页快捷功能栏。</p><h2 id="页面入口" tabindex="-1">页面入口 <a class="header-anchor" href="#页面入口" aria-label="Permalink to &quot;页面入口&quot;">​</a></h2><p>资产页 → 快捷功能栏「全部功能」</p><hr><h2 id="资金" tabindex="-1">资金 <a class="header-anchor" href="#资金" aria-label="Permalink to &quot;资金&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>存入资金</td><td>从绑定银行账户将资金转入长桥账户，支持 HKD、USD 等币种</td></tr><tr><td>提取资金</td><td>将长桥账户资金出金至已绑定的银行账户</td></tr><tr><td>货币兑换</td><td>在账户内将一种货币兑换为另一种货币（如 HKD ↔ USD）</td></tr><tr><td>资金划转</td><td>账户内部或账户之间的资金转移，支持三种类型（见下方说明）</td></tr><tr><td>银行卡</td><td>管理绑定的银行卡，查看 eDDA 授权状态，添加或删除银行卡</td></tr></tbody></table><h3 id="资金划转类型" tabindex="-1">资金划转类型 <a class="header-anchor" href="#资金划转类型" aria-label="Permalink to &quot;资金划转类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>划转类型</th><th>适用场景</th></tr></thead><tbody><tr><td>账户间资金划转</td><td>同一主体下的现金账户与融资账户之间互划资金</td></tr><tr><td>主子账户资金划转</td><td>主账户与子账户之间互划资金</td></tr><tr><td>跨券商资金划转</td><td>长桥证券（香港）与长桥证券（新加坡）之间跨主体划转</td></tr></tbody></table><hr><h2 id="股票" tabindex="-1">股票 <a class="header-anchor" href="#股票" aria-label="Permalink to &quot;股票&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>转入股票</td><td>从其他券商将持仓股票转入长桥账户（股票转仓）</td></tr><tr><td>转出股票</td><td>将长桥账户的股票持仓转出至其他券商</td></tr><tr><td>股票划转</td><td>在长桥主账户与子账户之间划转股票持仓</td></tr></tbody></table><hr><h2 id="交易" tabindex="-1">交易 <a class="header-anchor" href="#交易" aria-label="Permalink to &quot;交易&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>交易大厅</td><td>快速下单入口，汇集港股、美股等市场的交易操作</td></tr><tr><td>新股申购</td><td>查看当前可认购的新股（IPO）列表，并发起申购</td></tr><tr><td>股票定投</td><td>设置定期定额买入指定股票的自动投资计划</td></tr></tbody></table><hr><h2 id="记录" tabindex="-1">记录 <a class="header-anchor" href="#记录" aria-label="Permalink to &quot;记录&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>订单查询</td><td>查看当日委托和历史订单的成交状态</td></tr><tr><td>资金记录</td><td>查看账户的入金、出金、换汇、划转等资金流水记录</td></tr><tr><td>持仓日报</td><td>查看每日持仓快照，了解历史某日的持仓情况</td></tr><tr><td>盈亏分析</td><td>查看持仓和历史交易的盈亏分析报告，包括分品种、分时间段的盈亏拆解</td></tr><tr><td>结单查询</td><td>下载或查看月度、年度账户结算单</td></tr></tbody></table><hr><h2 id="理财" tabindex="-1">理财 <a class="header-anchor" href="#理财" aria-label="Permalink to &quot;理财&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>余额通</td><td>进入余额通增值计划管理页，查看闲置资金申购情况</td></tr></tbody></table><hr><h2 id="公司行动" tabindex="-1">公司行动 <a class="header-anchor" href="#公司行动" aria-label="Permalink to &quot;公司行动&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>选股选息</td><td>当公司提供以股代息选项时，在此选择接收现金或股票</td></tr><tr><td>供股要约</td><td>处理持仓股票的供股（配股）操作，在截止日期前选择认购或放弃</td></tr><tr><td>股东大会</td><td>查看持仓公司的股东大会（AGM/EGM）议案，进行网上投票</td></tr></tbody></table><hr><h2 id="账户" tabindex="-1">账户 <a class="header-anchor" href="#账户" aria-label="Permalink to &quot;账户&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>账户证明</td><td>申请或下载账户持有证明文件</td></tr><tr><td>开户资料</td><td>查看开户时提交的个人资料和账户基本信息</td></tr><tr><td>风险水平</td><td>查看当前账户的风险评级，以及是否需要重新评估</td></tr><tr><td>我的费率</td><td>查看当前账户适用的实际交易费率（港股、美股、期权、加密货币、融资利率）</td></tr><tr><td>主子账户</td><td>管理主账户与子账户的关联关系</td></tr><tr><td>PI 专区</td><td>专业投资者（PI）专属功能和产品入口</td></tr><tr><td>客户协议</td><td>查看账户开户时签署的客户协议文件</td></tr><tr><td>更新文件</td><td>提交或更新账户所需的身份证明、地址证明等文件</td></tr></tbody></table><hr><h2 id="设置" tabindex="-1">设置 <a class="header-anchor" href="#设置" aria-label="Permalink to &quot;设置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>资产设置</td><td>自定义持仓列表的列头显示、成本计算方式、美股/期权价格设置等显示偏好</td></tr></tbody></table>',30)])])}const f=d(h,[["render",o]]);export{u as __pageData,f as default};
